//icons
import { IconContext } from 'react-icons/lib';
import * as FaIcons from "react-icons/fa";
import { useState } from 'react';

const FaPlusCircle = <FaIcons.FaPlusCircle size = {40}/>
const FaChevronDown = <FaIcons.FaChevronDown size = {40} />
const FaChevronRight = <FaIcons.FaChevronRight size = {40} />
const FaBirthdayCake = <FaIcons.FaBirthdayCake size = {40} />

function BuscaPorId(props){  
    const [campoDeBusca, setCampoDeBusca] = useState('');


    function buscar(event){
        setCampoDeBusca(event.target.value);
        //props.consultaEventos(event.target.value);
    }

    function handleAberturaNovoEvento(){
        //props.gerarNovoEvento(); 
        //props.fecharOpcoesEventos(0);
    }

    return(
        <div className='espacoDireita flexNaoResponsivo'>
            <div className= 'btnNovoEvento flexNaoResponsivo'  onClick={handleAberturaNovoEvento} id='divBotaoAddEvento'>
                <div>
                    {FaPlusCircle}
                </div>
                <div>
                    Adicionar novo evento
                </div>
            </div>
            <form className="responsiva" >
                <div className= 'tituloBuscaEvento'>           
                    <p>
                        Id ou nome do cliente
                    </p>      
                </div>
                <div>
                    <input label='id' id="campoDeBuscaEventoPorId" type='text'className='form-evento' value={campoDeBusca} onChange={ buscar }/>
                </div>
            </form>            
        </div>                   
    );
}

function ComponenteBuscaPorData(props){
    const [dataDe, setDataDe] = useState('');
    const [dataAte, setDataAte] = useState('');

    function manipuladorDeData(){
        let dataDe = document.getElementById('dataDe').value;
        setDataDe(dataDe);
        let dataAte = document.getElementById('dataAte').value;
        setDataAte(dataAte);
        //props.consultaEventos({dataDe, dataAte});
    }
 
    return(
        <div className='espacoDireita espacoAntes'>
            
            <div className="flexNaoResponsivo">
                <h5>
                    Busca por datas:
                </h5>                
                <div>
                    <div>
                        <span>De:</span>
                        <input type='date' id='dataDe' value={dataDe} onChange={manipuladorDeData} className='form-evento'/>               
                    </div>
                    <div>
                        <span>Até:</span>
                        <input type='date' id='dataAte' value={dataAte} onChange={manipuladorDeData} className='form-evento'/>
                    </div>
                </div>                        
            </div>
            <div className='espacoDireita espacoAntes'>
                <button className='btn btn-secondary'> Próximos Evento &gt;&gt;</button>
            </div>                            
        </div>
    )  
   
    
}

function HandleEventos(props){
    const [painelAberto, setPainelAberto] = useState(false);
    const [iconePainel, setIconePainel] = useState(<FaIcons.FaChevronUp size = {40} />);

    function controlePainel(){
        if(painelAberto){
            setPainelAberto(false)
            setIconePainel(FaChevronRight);
        }else{
            setPainelAberto(true)
            setIconePainel(FaChevronDown);            
        }
    }  
   
    
    return (
        <div className='PainelDeControle espacoAntes padding5px '>
            <BuscaPorId />
            <ComponenteBuscaPorData />            
        </div>
    );
    
}

export default HandleEventos;
